function buildImageRecognizeCloudPath() {
  return 'ai-recognize/' + Date.now() + '_' + Math.random().toString(36).slice(2, 8) + '.jpg'
}

async function chooseImageForRecognize() {
  var res = await wx.chooseMedia({
    count: 1,
    mediaType: ['image'],
    sourceType: ['album', 'camera'],
    camera: 'back'
  })

  var tempFile = res && res.tempFiles && res.tempFiles[0]
  var tempPath = tempFile && tempFile.tempFilePath ? tempFile.tempFilePath : ''
  if (!tempPath) {
    throw new Error('未获取到图片')
  }

  return {
    tempPath: tempPath,
    rawResult: res
  }
}

async function uploadRecognizeImage(tempPath) {
  var uploadRes = await wx.cloud.uploadFile({
    cloudPath: buildImageRecognizeCloudPath(),
    filePath: tempPath
  })

  if (!uploadRes || !uploadRes.fileID) {
    throw new Error('图片上传失败')
  }

  return {
    fileID: uploadRes.fileID,
    uploadRes: uploadRes
  }
}

async function getRecognizeImageUrl(fileID) {
  var urlRes = await wx.cloud.getTempFileURL({ fileList: [fileID] })
  var fileItem = urlRes && urlRes.fileList && urlRes.fileList[0]
  var imageUrl = fileItem && fileItem.tempFileURL ? fileItem.tempFileURL : ''
  if (!imageUrl) {
    throw new Error('未获取到图片链接')
  }
  return imageUrl
}

function normalizeRecognizeResult(result) {
  var safeResult = result || {}
  return safeResult.parsed || { rocketName: '识别结果', description: safeResult.raw || '识别完成' }
}

function cleanupRecognizeFile(fileID) {
  if (!fileID) return Promise.resolve()
  return wx.cloud.deleteFile({ fileList: [fileID] }).catch(function () {})
}

async function runImageRecognizeFlow(options) {
  var opts = options || {}
  var recognizeImage = opts.recognizeImage
  var onChosen = opts.onChosen
  if (typeof recognizeImage !== 'function') {
    throw new Error('缺少图片识别函数')
  }

  var chosen = await chooseImageForRecognize()
  if (typeof onChosen === 'function') {
    await onChosen(chosen.tempPath, chosen.rawResult)
  }

  var uploaded = await uploadRecognizeImage(chosen.tempPath)
  var fileID = uploaded.fileID

  try {
    var imageUrl = await getRecognizeImageUrl(fileID)
    var result = await recognizeImage(imageUrl)
    return {
      tempPath: chosen.tempPath,
      fileID: fileID,
      imageUrl: imageUrl,
      rawResult: result,
      parsedResult: normalizeRecognizeResult(result)
    }
  } finally {
    cleanupRecognizeFile(fileID)
  }
}

module.exports = {
  chooseImageForRecognize,
  uploadRecognizeImage,
  getRecognizeImageUrl,
  normalizeRecognizeResult,
  cleanupRecognizeFile,
  runImageRecognizeFlow
}
