const IR_CLOSE_DELAY_MS = 260
const IR_BOUNCE_DURATION_MS = 400
const IR_CLOSE_THRESHOLD = 110
const IR_MAX_DRAG = 360
const IR_DAMPING_FACTOR = 180
const IR_BOUNCE_SHADOW = 'box-shadow: 0 -12rpx 60rpx rgba(0,0,0,0.65);'

function buildImageRecognizeLoadingState(tempPath) {
  return {
    recognizedImagePath: tempPath || '',
    imageRecognizeLoading: true,
    imageRecognizeResult: null,
    searchLoading: false
  }
}

function buildImageRecognizeSuccessState(result) {
  return {
    imageRecognizeResult: result || null,
    imageRecognizeLoading: false,
    showImageRecognizeModal: true,
    irDragOffset: 0,
    irPopupPhase: 'ir-enter',
    irBounceExtra: '',
    showSearchModal: false
  }
}

function buildImageRecognizeIdleState(extraState) {
  return {
    imageRecognizeLoading: false,
    ...(extraState && typeof extraState === 'object' ? extraState : {})
  }
}

function buildImageRecognizeClearState() {
  return {
    imageRecognizeResult: null,
    recognizedImagePath: ''
  }
}

function buildImageRecognizeClosingState() {
  return {
    irPopupPhase: 'ir-leave'
  }
}

function buildImageRecognizeClosedState() {
  return {
    showImageRecognizeModal: false,
    irDragOffset: 0,
    irPopupPhase: '',
    irBounceExtra: '',
    imageRecognizeResult: null,
    recognizedImagePath: ''
  }
}

function getRecognizeSearchKeyword(result) {
  const rocketName = result && result.rocketName ? String(result.rocketName).trim() : ''
  if (!rocketName || rocketName === '识别结果') {
    return ''
  }
  return rocketName
}

function buildRecognizeSearchEntryState(keyword) {
  return {
    showSearchModal: true,
    searchKeyword: keyword || ''
  }
}

function buildImageRecognizeDraggingState() {
  return {
    irPopupPhase: 'ir-dragging',
    irBounceExtra: ''
  }
}

function getImageRecognizeDampedOffset(rawDistance) {
  const raw = Math.max(0, Number(rawDistance) || 0)
  return IR_MAX_DRAG * (1 - Math.exp(-raw / IR_DAMPING_FACTOR))
}

function buildImageRecognizeDragOffsetState(offset) {
  return {
    irDragOffset: offset
  }
}

function shouldCloseImageRecognizeModal(offset) {
  return Number(offset) > IR_CLOSE_THRESHOLD
}

function buildImageRecognizeBounceState() {
  return {
    irPopupPhase: 'ir-bounce',
    irDragOffset: 0,
    irBounceExtra: IR_BOUNCE_SHADOW
  }
}

function buildImageRecognizeEnterState() {
  return {
    irPopupPhase: 'ir-enter',
    irBounceExtra: ''
  }
}

module.exports = {
  IR_CLOSE_DELAY_MS,
  IR_BOUNCE_DURATION_MS,
  buildImageRecognizeLoadingState,
  buildImageRecognizeSuccessState,
  buildImageRecognizeIdleState,
  buildImageRecognizeClearState,
  buildImageRecognizeClosingState,
  buildImageRecognizeClosedState,
  getRecognizeSearchKeyword,
  buildRecognizeSearchEntryState,
  buildImageRecognizeDraggingState,
  getImageRecognizeDampedOffset,
  buildImageRecognizeDragOffsetState,
  shouldCloseImageRecognizeModal,
  buildImageRecognizeBounceState,
  buildImageRecognizeEnterState
}
